DIM   = [0,31,28,31,30,31,30,31,31,30,31,30,31]
EMOJI = {"A":"☀","B":"☁","C":"🌧"}
WX    = {"A":"맑음","B":"흐림","C":"비"}
MONTHS= ["","1월","2월","3월","4월","5월","6월","7월","8월","9월","10월","11월","12월"]
DAYS  = ["월","화","수","목","금","토","일"]


def build_calendar(m, cur_f):
    """월별 달력 주(week) 배열 생성"""
    by_day = {r["d"]: r for r in WEATHER_DATA if r["m"] == m}
    first_dow = date(2025, m, 1).weekday()   # 0=월
    cells = [None] * first_dow + list(range(1, DIM[m] + 1))
    while len(cells) % 7:
        cells.append(None)

    weeks = []
    for w in range(len(cells) // 7):
        week = []
        for i in range(7):
            day = cells[w * 7 + i]
            if day is None:
                week.append(None)
                continue
            r = by_day.get(day)
            if r:
                cell = dict(r)
                cell["dow"] = i          # 0=월 5=토 6=일
                cell["emoji_fc"]  = EMOJI[r["fc"]]
                cell["emoji_act"] = EMOJI[r["act"]]
                cell["wx_fc"]  = WX[r["fc"]]
                cell["wx_act"] = WX[r["act"]]
            else:
                cell = {"d": day, "dow": i, "ok": False,
                        "fc":"A","act":"A","prob":0,"mm":0.0,
                        "emoji_fc":"","emoji_act":"","wx_fc":"","wx_act":""}
            week.append(cell)
        weeks.append(week)
    return weeks


def month_stats(m):
    md = [r for r in WEATHER_DATA if r["m"] == m]
    ok = sum(1 for r in md if r["ok"])
    total = len(md)
    return {
        "ok": ok, "miss": total - ok,
        "acc": round(ok / total * 100) if total else 0,
        "mm":  round(sum(r["mm"] for r in md), 1),
        "fcA": sum(1 for r in md if r["fc"]  == "A"),
        "fcB": sum(1 for r in md if r["fc"]  == "B"),
        "fcC": sum(1 for r in md if r["fc"]  == "C"),
        "acA": sum(1 for r in md if r["act"] == "A"),
        "acB": sum(1 for r in md if r["act"] == "B"),
        "acC": sum(1 for r in md if r["act"] == "C"),
    }


def annual_stats():
    ok    = sum(1 for r in WEATHER_DATA if r["ok"])
    total = len(WEATHER_DATA)
    return {
        "acc":  round(ok / total * 100),
        "ok":   ok,
        "miss": total - ok,
        "fcA":  sum(1 for r in WEATHER_DATA if r["fc"]  == "A"),
        "fcB":  sum(1 for r in WEATHER_DATA if r["fc"]  == "B"),
        "fcC":  sum(1 for r in WEATHER_DATA if r["fc"]  == "C"),
        "acA":  sum(1 for r in WEATHER_DATA if r["act"] == "A"),
        "acB":  sum(1 for r in WEATHER_DATA if r["act"] == "B"),
        "acC":  sum(1 for r in WEATHER_DATA if r["act"] == "C"),
        "mm":   round(sum(r["mm"] for r in WEATHER_DATA), 1),
    }


